parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "invoiceNumber": {
      "type": "string",
      "description": "The invoice number"
    },
    "invoiceDate": {
      "type": "string",
      "description": "The invoice date in YYYY-MM-DD format"
    },
    "vendorName": {
      "type": "string",
      "description": "The name of the vendor"
    },
    "currency": {
      "type": "string",
      "description": "3-letter currency code (e.g., USD, EUR, GBP)"
    },
    "totalAmount": {
      "type": "number",
      "description": "The total amount of the invoice"
    },
    "lineItems": {
      "type": "array",
      "description": "Array of line items in the invoice",
      "items": {
        "type": "object",
        "properties": {
          "description": {
            "type": "string",
            "description": "Description of the line item"
          },
          "quantity": {
            "type": "number",
            "description": "Quantity of the item"
          },
          "unitPrice": {
            "type": "number",
            "description": "Unit price of the item"
          },
          "amount": {
            "type": "number",
            "description": "Total amount for the line item"
          }
        }
      }
    },
    "taxAmount": {
      "type": "number",
      "description": "The tax amount"
    },
    "subtotal": {
      "type": "number",
      "description": "The subtotal before tax"
    }
  }
}

parameters.jsCode:
// Validate invoice data
const invoiceData = $input.item.json;

// Initialize validation result
const validationResult = {
  isValid: true,
  errors: []
};

// Get valid currencies from Workflow Configuration node
const validCurrencies = $('Workflow Configuration').item.json.validCurrencies || ['USD', 'EUR', 'GBP'];

// Validate date format (YYYY-MM-DD)
const dateRegex = /^\d{4}-\d{2}-\d{2}$/;
if (!invoiceData.date || !dateRegex.test(invoiceData.date)) {
  validationResult.isValid = false;
  validationResult.errors.push('Invalid date format. Expected YYYY-MM-DD');
}

// Validate currency is in valid list
if (!invoiceData.currency || !validCurrencies.includes(invoiceData.currency)) {
  validationResult.isValid = false;
  validationResult.errors.push(`Invalid currency. Must be one of: ${validCurrencies.join(', ')}`);
}

// Validate total amount is greater than zero
const totalAmount = parseFloat(invoiceData.totalAmount);
if (isNaN(totalAmount) || totalAmount <= 0) {
  validationResult.isValid = false;
  validationResult.errors.push('Total amount must be greater than zero');
}

// Return the validation result along with original invoice data
return {
  ...invoiceData,
  validation: validationResult
};
